interface.definition:
#"SYSTEM_SYSRULES_headerContentLayout"(
  header: #"SYSTEM_SYSRULES_cardLayout"(
    contents: {
      #"SYSTEM_SYSRULES_sideBySideLayout"(
        items: {
          #"SYSTEM_SYSRULES_sideBySideItem"(
            width: "MINIMIZE",
            item: #"SYSTEM_SYSRULES_richTextDisplayField"(
              labelPosition: "COLLAPSED",
              value: {
                #"SYSTEM_SYSRULES_richTextIcon"(
                  icon: "exclamation-triangle",
                  color: "NEGATIVE",
                  size: "LARGE"
                )
              },
              marginBelow: "NONE"
            )
          ),
          #"SYSTEM_SYSRULES_sideBySideItem"(
            item: #"SYSTEM_SYSRULES_headingField"(
              text: "Delete Participant?",
              size: "MEDIUM_PLUS",
              fontWeight: "SEMI_BOLD",
              marginBelow: "NONE"
            )
          )
        },
        alignVertical: "MIDDLE"
      )
    },
    padding: "MORE",
    showBorder: false,
    style: "ERROR"
  ),
  contents: {
    #"SYSTEM_SYSRULES_columnsLayout"(
      columns: {
        #"SYSTEM_SYSRULES_columnLayout"(
          contents: {}
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          width: "WIDE",
          contents: {
            #"SYSTEM_SYSRULES_sectionLayout_v1"(
              contents: {
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  contents: {
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      labelPosition: "COLLAPSED",
                      value: {
                        "The participant will be permanently deleted and cannot be recovered"
                      },
                      marginBelow: "MORE",
                      align: "LEFT"
                    )
                  },
                  marginBelow: "LESS"
                ),
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  contents: {
                    #"SYSTEM_SYSRULES_ButtonLayout"(
                      primaryButtons: {
                        #"SYSTEM_SYSRULES_buttonWidget_v1"(
                          label: "Delete",
                          submit: true,
                          style: "SOLID",
                          color: "NEGATIVE"
                        )
                      },
                      secondaryButtons: {
                        #"SYSTEM_SYSRULES_buttonWidget_v1"(
                          label: "Cancel",
                          submit: true,
                          validate: false,
                          saveInto: ri!cancel,
                          style: "OUTLINE",
                          color: "SECONDARY",
                          value: true
                        )
                      }
                    )
                  },
                  marginBelow: "NONE",
                  marginAbove: "EVEN_MORE"
                )
              },
              marginBelow: "NONE"
            )
          }
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          contents: {}
        )
      }
    )
  },
  backgroundColor: "#fbfbfb",
  contentsPadding: "MORE"
)
